export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): Array<Record<string, any>>;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Array<Record<string, any>>>;
}

function coerceValue(value: string): any {
  const trimmed = value.trim();
  if (trimmed === "" || /^null$/i.test(trimmed)) {
    return null;
  }
  if (/^true$/i.test(trimmed)) {
    return true;
  }
  if (/^false$/i.test(trimmed)) {
    return false;
  }
  if (/^-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?$/.test(trimmed)) {
    return Number(trimmed);
  }
  return value;
}

function startsWithAt(input: string, index: number, token: string): boolean {
  return input.substr(index, token.length) === token;
}

function parseRows(input: string, delimiter: string, quoteChar: string, lineSeparator: string, errors: CSVError[]): string[][] {
  const rows: string[][] = [];
  let currentRow: string[] = [];
  let currentField = "";
  let inQuotes = false;
  let i = 0;
  let rowNumber = 1;
  let lastTokenWasLineSeparator = false;

  const pushField = () => {
    currentRow.push(currentField);
    currentField = "";
  };

  while (i < input.length) {
    lastTokenWasLineSeparator = false;
    if (inQuotes) {
      if (startsWithAt(input, i, quoteChar)) {
        if (startsWithAt(input, i, quoteChar + quoteChar)) {
          currentField += quoteChar;
          i += quoteChar.length * 2;
          continue;
        }
        inQuotes = false;
        i += quoteChar.length;
        continue;
      }
      currentField += input[i];
      i += 1;
      continue;
    }

    if (startsWithAt(input, i, lineSeparator)) {
      pushField();
      rows.push(currentRow);
      currentRow = [];
      i += lineSeparator.length;
      rowNumber += 1;
      lastTokenWasLineSeparator = true;
      continue;
    }

    if (startsWithAt(input, i, delimiter)) {
      pushField();
      i += delimiter.length;
      continue;
    }

    if (startsWithAt(input, i, quoteChar)) {
      inQuotes = true;
      i += quoteChar.length;
      continue;
    }

    currentField += input[i];
    i += 1;
  }

  if (inQuotes) {
    errors.push({ row: rowNumber, message: "Unclosed quote in row" });
  }

  if (!lastTokenWasLineSeparator && (currentRow.length > 0 || currentField.length > 0 || input.length > 0)) {
    pushField();
    rows.push(currentRow);
  }

  return rows;
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? "\n";
  const errors: CSVError[] = [];

  let normalizedInput = input;
  if (lineSeparator === "\n") {
    normalizedInput = normalizedInput.replace(/\r\n/g, "\n");
  }

  if (normalizedInput.length === 0) {
    return {
      rows: [],
      headers: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
  }

  const rawRows = parseRows(normalizedInput, delimiter, quoteChar, lineSeparator, errors);
  const headers = (rawRows[0] ?? []).map((header) => header.trim());
  const dataRows = rawRows.slice(1);

  const rows: Array<Record<string, any>> = dataRows.map((row, index) => {
    const rowNumber = index + 2;
    if (row.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Row has ${row.length} columns, expected ${headers.length}`,
      });
    }

    const record: Record<string, any> = {};
    for (let i = 0; i < headers.length; i += 1) {
      const value = row[i] ?? "";
      record[headers[i]] = coerceValue(value);
    }
    return record;
  });

  const filter = (predicate: (row: Record<string, any>) => boolean) => rows.filter(predicate);
  const sum = (column: string) =>
    rows.reduce((total, row) => (typeof row[column] === "number" ? total + row[column] : total), 0);
  const average = (column: string) => {
    let total = 0;
    let count = 0;
    for (const row of rows) {
      if (typeof row[column] === "number") {
        total += row[column];
        count += 1;
      }
    }
    return count === 0 ? 0 : total / count;
  };
  const count = () => rows.length;
  const groupBy = (column: string) => {
    const grouped = new Map<any, Array<Record<string, any>>>();
    for (const row of rows) {
      const key = row[column];
      const existing = grouped.get(key) ?? [];
      existing.push(row);
      grouped.set(key, existing);
    }
    return grouped;
  };

  return { rows, headers, errors, filter, sum, average, count, groupBy };
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string) {
  if (!condition) {
    throw new Error(message);
  }
}

function deepEqual(actual: any, expected: any, path: string[] = []) {
  const currentPath = path.length ? path.join(".") : "value";
  if (actual === expected) {
    return;
  }
  if (typeof actual !== typeof expected) {
    throw new Error(`Type mismatch at ${currentPath}`);
  }
  if (actual === null || expected === null) {
    throw new Error(`Null mismatch at ${currentPath}`);
  }
  if (Array.isArray(actual)) {
    assert(Array.isArray(expected), `Expected array at ${currentPath}`);
    assert(actual.length === expected.length, `Array length mismatch at ${currentPath}`);
    for (let i = 0; i < actual.length; i += 1) {
      deepEqual(actual[i], expected[i], path.concat(String(i)));
    }
    return;
  }
  if (typeof actual === "object") {
    const actualKeys = Object.keys(actual).sort();
    const expectedKeys = Object.keys(expected).sort();
    deepEqual(actualKeys, expectedKeys, path.concat("keys"));
    for (const key of actualKeys) {
      deepEqual(actual[key], expected[key], path.concat(key));
    }
    return;
  }
  throw new Error(`Value mismatch at ${currentPath}`);
}

// Basic parsing
{
  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  deepEqual(result.headers, ["name", "age"]);
  assert(result.rows.length === 2, "Expected two rows");
  deepEqual(result.rows[0], { name: "Alice", age: 30 });
  deepEqual(result.rows[1], { name: "Bob", age: 25 });
  assert(result.errors.length === 0, "Expected no errors in basic parsing");
}

// Quoted fields with commas
{
  const input = "name,description\n\"Widget, Large\",Useful";
  const result = parseCSV(input);
  deepEqual(result.rows[0], { name: "Widget, Large", description: "Useful" });
}

// Escaped quotes
{
  const input = "name,quote\nAlice,\"She said \"\"Hello\"\"\"";
  const result = parseCSV(input);
  deepEqual(result.rows[0], { name: "Alice", quote: "She said \"Hello\"" });
}

// Custom delimiters and line separators
{
  const input = "name;age|Alice;30|Bob;'25'";
  const result = parseCSV(input, { delimiter: ";", lineSeparator: "|", quoteChar: "'" });
  deepEqual(result.headers, ["name", "age"]);
  deepEqual(result.rows[0], { name: "Alice", age: 30 });
  deepEqual(result.rows[1], { name: "Bob", age: 25 });
}

// Type coercion for numbers, booleans, nulls, and strings
{
  const input = "value\n123\n45.6\ntrue\nFALSE\nnull\n\ntext";
  const result = parseCSV(input);
  const values = result.rows.map((row) => row.value);
  deepEqual(values, [123, 45.6, true, false, null, null, "text"]);
}

// Malformed row error collection
{
  const input = "a,b\n1,2,3\n4";
  const result = parseCSV(input);
  assert(result.errors.length === 2, "Expected two errors for malformed rows");
  assert(result.errors[0].row === 2, "Expected error on row 2");
  assert(result.errors[1].row === 3, "Expected error on row 3");
  deepEqual(result.rows[0], { a: 1, b: 2 });
  deepEqual(result.rows[1], { a: 4, b: null });
}

// Filtering
{
  const input = "name,age\nAlice,30\nBob,20\nCara,40";
  const result = parseCSV(input);
  const filtered = result.filter((row) => row.age > 25);
  deepEqual(filtered, [{ name: "Alice", age: 30 }, { name: "Cara", age: 40 }]);
}

// Aggregation methods
{
  const input = "name,score,city\nAlice,10,NY\nBob,20,SF\nCara,30,NY";
  const result = parseCSV(input);
  assert(result.count() === 3, "Expected count to be 3");
  assert(result.sum("score") === 60, "Expected sum to be 60");
  assert(result.average("score") === 20, "Expected average to be 20");
  const grouped = result.groupBy("city");
  assert(grouped.get("NY")?.length === 2, "Expected two rows for NY");
  assert(grouped.get("SF")?.length === 1, "Expected one row for SF");
}

// Edge cases: empty input
{
  const result = parseCSV("");
  deepEqual(result.headers, []);
  deepEqual(result.rows, []);
  assert(result.errors.length === 0, "Expected no errors for empty input");
}

// Edge cases: single column
{
  const input = "name\nAlice\nBob";
  const result = parseCSV(input);
  deepEqual(result.rows, [{ name: "Alice" }, { name: "Bob" }]);
}

// Edge cases: single row
{
  const input = "name,age\nAlice,30";
  const result = parseCSV(input);
  deepEqual(result.rows, [{ name: "Alice", age: 30 }]);
}

// Edge cases: very large fields
{
  const largeValue = "a".repeat(10000);
  const input = `col\n\"${largeValue}\"`;
  const result = parseCSV(input);
  assert(result.rows[0].col.length === 10000, "Expected large field to be preserved");
}

console.log("All tests passed.");

