  return input.substr(index, token.length) === token;
}

function parseRows(input: string, delimiter: string, quoteChar: string, lineSeparator: string, errors: CSVError[]): string[][] {
  const rows: string[][] = [];
  let currentRow: string[] = [];
  let currentField = "";
  let inQuotes = false;
  let i = 0;
  let rowNumber = 1;
  let lastTokenWasLineSeparator = false;

  const pushField = () => {
    currentRow.push(currentField);
    currentField = "";
  };

  while (i < input.length) {
    lastTokenWasLineSeparator = false;
    if (inQuotes) {
      if (startsWithAt(input, i, quoteChar)) {
        if (startsWithAt(input, i, quoteChar + quoteChar)) {
          currentField += quoteChar;
          i += quoteChar.length * 2;
          continue;
        }
        inQuotes = false;
        i += quoteChar.length;
        continue;
      }
      currentField += input[i];
      i += 1;
      continue;
    }

    if (startsWithAt(input, i, lineSeparator)) {
      pushField();
      rows.push(currentRow);
      currentRow = [];
      i += lineSeparator.length;
      rowNumber += 1;
      lastTokenWasLineSeparator = true;
      continue;
    }

    if (startsWithAt(input, i, delimiter)) {
      pushField();
      i += delimiter.length;
      continue;
    }

    if (startsWithAt(input, i, quoteChar)) {
      inQuotes = true;
      i += quoteChar.length;
      continue;
    }

    currentField += input[i];
    i += 1;
  }

  if (inQuotes) {
    errors.push({ row: rowNumber, message: "Unclosed quote in row" });
  }

  if (!lastTokenWasLineSeparator && (currentRow.length > 0 || currentField.length > 0 || input.length > 0)) {
    pushField();
    rows.push(currentRow);
  }

  return rows;
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? "\n";
  const errors: CSVError[] = [];

  let normalizedInput = input;
  if (lineSeparator === "\n") {
    normalizedInput = normalizedInput.replace(/\r\n/g, "\n");
  }

  if (normalizedInput.length === 0) {
    return {
      rows: [],
      headers: [],
      errors: [],
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
  }

  const rawRows = parseRows(normalizedInput, delimiter, quoteChar, lineSeparator, errors);
  const headers = (rawRows[0] ?? []).map((header) => header.trim());
  const dataRows = rawRows.slice(1);

  const rows: Array<Record<string, any>> = dataRows.map((row, index) => {
    const rowNumber = index + 2;
    if (row.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Row has ${row.length} columns, expected ${headers.length}`,
      });
