    const record: Record<string, any> = {};
    for (let i = 0; i < headers.length; i += 1) {
      const value = row[i] ?? "";
      record[headers[i]] = coerceValue(value);
    }
    return record;
  });

  const filter = (predicate: (row: Record<string, any>) => boolean) => rows.filter(predicate);
  const sum = (column: string) =>
    rows.reduce((total, row) => (typeof row[column] === "number" ? total + row[column] : total), 0);
  const average = (column: string) => {
    let total = 0;
    let count = 0;
    for (const row of rows) {
      if (typeof row[column] === "number") {
        total += row[column];
        count += 1;
      }
    }
    return count === 0 ? 0 : total / count;
  };
  const count = () => rows.length;
  const groupBy = (column: string) => {
    const grouped = new Map<any, Array<Record<string, any>>>();
    for (const row of rows) {
      const key = row[column];
      const existing = grouped.get(key) ?? [];
      existing.push(row);
      grouped.set(key, existing);
    }
    return grouped;
  };

  return { rows, headers, errors, filter, sum, average, count, groupBy };
}
